                    className="flex-1 px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
                  />
                  <button
                    onClick={() => {
                      if (newChecklistItem.trim()) {
                        addChecklistItem(task.id, newChecklistItem.trim());
                        setNewChecklistItem('');
                      }
                    }}
                    className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white text-sm font-medium rounded-lg transition-colors"
                  >
                    Add
                  </button>
                </div>
              </div>
            )}

            {activeTab === 'comments' && (
              <div className="space-y-4">
                {/* Comments List */}
                <div className="space-y-3 max-h-[400px] overflow-y-auto">
                  {task.comments && task.comments.length > 0 ? (
                    task.comments
                      .sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime())
                      .map((comment) => (
                        <div key={comment.id} className="bg-surface-light-elevated dark:bg-surface-dark p-3 rounded-lg">
                          <div className="flex justify-between items-start mb-2">
                            <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">{comment.author}</span>
                            <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                              {new Date(comment.createdAt).toLocaleString()}
                            </span>
                          </div>
                          <p className="text-sm text-text-light-primary dark:text-text-dark-primary whitespace-pre-wrap">{comment.text}</p>
                        </div>
                      ))
                  ) : (
                    <div className="text-center py-2 text-text-light-secondary dark:text-text-dark-secondary text-xs">
                      💬 No comments yet
                    </div>
                  )}
                </div>

                {/* Add Comment Form */}
                <div className="space-y-2">
                  <textarea
                    value={newCommentText}
                    onChange={(e) => setNewCommentText(e.target.value)}
                    placeholder="Add a comment..."
                    className="w-full p-3 text-sm border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none resize-y"
                    rows={3}
                  />
                  <button
                    onClick={() => {
                      if (newCommentText.trim()) {
                        addComment(task.id, newCommentText.trim());
                        setNewCommentText('');
                      }
                    }}
                    className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white text-sm font-medium rounded-lg transition-colors"
                  >
                    Post Comment
                  </button>
                </div>
              </div>
            )}

            {activeTab === 'activity' && (
              <ActivityTabContent activityLog={task.activityLog} />
            )}

            {/* Time Tracking Tab (Phase A: Time Tracking Integration) */}
            {activeTab === 'timetracking' && task && (() => {
              const entries = getEntriesForCard(task.id);
              const totalSeconds = getTotalTimeForCard(task.id);
              const isTimerActive = activeEntry?.taskId === task.id;

              const formatDuration = (seconds: number): string => {
                const hours = Math.floor(seconds / 3600);
                const minutes = Math.floor((seconds % 3600) / 60);
                const secs = seconds % 60;
                return `${hours}h ${minutes}m ${secs}s`;
              };

              const formatTime = (seconds: number): string => {
                const hours = seconds / 3600;
                return hours < 0.1 ? '<0.1h' : `${hours.toFixed(1)}h`;
              };

              return (
                <div className="space-y-4">
                  {/* Timer Controls */}
                  <div className="bg-surface-light-elevated dark:bg-surface-dark rounded-lg p-4">
                    <div className="flex items-center justify-between mb-3">
                      <div>
                        <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
                          Total Time: {formatTime(totalSeconds)}
                        </h3>
                        <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                          {formatDuration(totalSeconds)}
                        </p>
                      </div>
                      {isTimerActive ? (
                        <button
                          onClick={() => stopTimer()}
                          className="px-4 py-2 bg-status-error text-white text-sm font-medium rounded-lg hover:bg-status-error/90 transition-colors flex items-center gap-2"
                        >
                          <span className="animate-pulse">⏱️</span>
                          Stop Timer
                        </button>
                      ) : (
                        <button
                          onClick={() => startTimerForCard(task.id, task.title)}
                          className="px-4 py-2 bg-accent-blue text-white text-sm font-medium rounded-lg hover:bg-accent-blue-hover transition-colors flex items-center gap-2"
                        >
                          ▶️ Start Timer
                        </button>
                      )}
                    </div>

                    {/* Estimated Hours Comparison */}
                    {task.estimatedHours && (
                      <div className="pt-3 border-t border-border-light dark:border-border-dark">
                        <div className="flex items-center justify-between text-xs">
                          <span className="text-text-light-secondary dark:text-text-dark-secondary">
                            Estimated: {task.estimatedHours}h
                          </span>
                          <span className={`font-medium ${
                            totalSeconds / 3600 > task.estimatedHours
                              ? 'text-status-error'
                              : 'text-status-success'
                          }`}>
                            {totalSeconds / 3600 > task.estimatedHours
                              ? `Over by ${((totalSeconds / 3600) - task.estimatedHours).toFixed(1)}h`
                              : `${(task.estimatedHours - (totalSeconds / 3600)).toFixed(1)}h remaining`
                            }
                          </span>
                        </div>
                        {/* Progress Bar */}
                        <div className="mt-2 w-full bg-neutral-200 dark:bg-neutral-700 rounded-full h-2">
                          <div
                            className={`h-2 rounded-full transition-all ${
                              totalSeconds / 3600 > task.estimatedHours
                                ? 'bg-status-error'
                                : 'bg-accent-blue'
                            }`}
                            style={{
                              width: `${Math.min(100, (totalSeconds / 3600 / task.estimatedHours) * 100)}%`,
                            }}
                          />
                        </div>
                      </div>
                    )}
                  </div>

                  {/* Time Entries List */}
                  <div>
                    <h4 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
                      Time Entries ({entries.length})
                    </h4>
                    {entries.length > 0 ? (
                      <div className="space-y-2 max-h-[400px] overflow-y-auto">
                        {entries.map((entry, index) => (
                          <div
                            key={entry.id || index}
                            className="bg-surface-light-elevated dark:bg-surface-dark rounded-lg p-3 border border-border-light dark:border-border-dark"
                          >
                            <div className="flex items-start justify-between gap-2">
                              <div className="flex-1">
                                <p className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
                                  {entry.description}
                                </p>
                                <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                                  {new Date(entry.startTime).toLocaleString()}
                                  {entry.endTime && ` - ${new Date(entry.endTime).toLocaleTimeString()}`}
                                </p>
                              </div>
                              <div className="text-right">
                                <p className={`text-sm font-semibold ${
                                  !entry.endTime
                                    ? 'text-accent-blue animate-pulse'
                                    : 'text-text-light-primary dark:text-text-dark-primary'
                                }`}>
                                  {formatTime(entry.duration)}
                                </p>
                                {!entry.endTime && (
                                  <p className="text-xs text-accent-blue">Running...</p>
                                )}
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>
                    ) : (
                      <div className="text-center py-2 text-text-light-secondary dark:text-text-dark-secondary text-xs">
                        ⏱️ No time entries yet
                      </div>
                    )}
                  </div>
                </div>
              );
            })()}

            {/* Attachments Tab (Phase 3.2) */}
            {activeTab === 'attachments' && task && (
              <div className="space-y-4">
                {/* File Upload */}
                <div>
                  <h4 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
                    Upload Files
                  </h4>
                  <FileUpload
                    onUpload={(file) => {
                      addAttachment(task.id, {
                        filename: file.filename,
                        fileType: file.fileType,
                        fileSize: file.fileSize,
                        dataUrl: file.dataUrl,
                      });
                    }}
                  />
                </div>

                {/* Attachment List */}
                <div>
                  <h4 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
                    Attachments ({task.attachments?.length || 0})
                  </h4>
                  <AttachmentList
                    attachments={task.attachments || []}
                    onDelete={(attachmentId) => deleteAttachment(task.id, attachmentId)}
                    onPreview={(attachment) => setPreviewAttachment(attachment)}
                  />
                </div>

                {/* Phase 3.4: Card Cover Mode Selector (only show when image attachments exist) */}
                {task.attachments?.some(a => a.fileType.startsWith('image/')) && (
                  <div>
                    <h4 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
                      Card Cover Display
                    </h4>
                    <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mb-2">
                      Choose how the first image appears on the card
                    </p>
                    <div className="flex gap-2">
                      <button
                        onClick={() => onSave(task.id, { coverMode: 'fit' })}
                        className={`flex-1 px-3 py-2 rounded-lg text-sm font-medium transition-colors ${
                          task.coverMode === 'fit' || !task.coverMode
                            ? 'bg-accent-blue text-white'
                            : 'bg-surface-light-elevated dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-100 dark:hover:bg-neutral-700'
                        }`}
                      >
                        Fit (show full image)
                      </button>
                      <button
                        onClick={() => onSave(task.id, { coverMode: 'fill' })}
                        className={`flex-1 px-3 py-2 rounded-lg text-sm font-medium transition-colors ${
                          task.coverMode === 'fill'
                            ? 'bg-accent-blue text-white'
                            : 'bg-surface-light-elevated dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-100 dark:hover:bg-neutral-700'
                        }`}
                      >
                        Fill (crop to fit)
                      </button>
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Footer: Keyboard Hints */}
      <div className="mt-2 pt-2 border-t border-border-light dark:border-border-dark">
        <p className="text-[10px] text-text-light-secondary dark:text-text-dark-secondary text-center">
          Press <kbd className="px-1 py-0.5 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded text-[10px]">Esc</kbd> to close
          or <kbd className="px-1 py-0.5 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded text-[10px]">Cmd+Enter</kbd> to save
        </p>
      </div>
    </Modal>

    {/* Phase 1.2: Dependent shift confirmation dialog */}
    {pendingShifts && pendingShifts.length > 0 && (
      <DependentShiftConfirmation
        shifts={pendingShifts}
        tasks={tasks}
        onConfirm={handleConfirmShifts}
        onCancel={handleCancelShifts}
        onDontAskAgain={handleDontAskAgain}
      />
    )}

    {/* Phase 3.2: Image preview modal */}
    {previewAttachment && (
      <ImagePreviewModal
        attachment={previewAttachment}
        onClose={() => setPreviewAttachment(null)}
      />
    )}
    </>
  );
};

