                      <span className="font-medium text-text-light-primary dark:text-text-dark-primary">Progress</span>
                      <span className="text-text-light-secondary dark:text-text-dark-secondary">
                        {task.checklist.filter(item => item.completed).length} of {task.checklist.length}
                      </span>
                    </div>
                    <div className="w-full bg-neutral-200 dark:bg-neutral-700 rounded-full h-2">
                      <div
                        className="bg-accent-blue h-2 rounded-full transition-all"
                        style={{ width: `${(task.checklist.filter(item => item.completed).length / task.checklist.length) * 100}%` }}
