     1→/**
     2→ * Provider Settings Modal
     3→ * Configure AI provider API keys with encryption
     4→ *
     5→ * Features:
     6→ * - Configure all 8 AI providers (OpenRouter, Groq, HuggingFace, Mistral, Gemini, OpenAI, Anthropic, xAI)
     7→ * - Encrypted API key storage
     8→ * - Visual provider status (configured/unconfigured)
     9→ * - Test API key validation
    10→ * - Provider documentation links
    11→ * - Free vs paid tier indicators
    12→ * - CORS compatibility warnings
    13→ */
    14→
    15→import { useState, useEffect } from 'react';
    16→import { Modal } from './Modal';
    17→import { PasswordPrompt } from './PasswordPrompt';
    18→import { useTerminalStore } from '../stores/useTerminalStore';
    19→import { AIProviderRouter, PROVIDER_METADATA } from '../services/ai/providerRouter';
    20→
    21→interface ProviderSettingsProps {
    22→  isOpen: boolean;
    23→  onClose: () => void;
    24→  router: AIProviderRouter;
    25→}
    26→
    27→export function ProviderSettings({ isOpen, onClose, router }: ProviderSettingsProps) {
    28→  const {
    29→    // providers is unused (using router.getAllProviders() instead)
    30→    encryptionPassword,
    31→    passwordHash,
    32→    isPasswordExpired,
    33→    setProviderApiKey,
    34→    clearProviderApiKey,
    35→    setEncryptionPassword,
    36→    setActiveProvider,
    37→  } = useTerminalStore();
    38→
    39→  const [showPasswordPrompt, setShowPasswordPrompt] = useState(false);
    40→  const [selectedProvider, setSelectedProvider] = useState<string | null>(null);
    41→  const [apiKeyInputs, setApiKeyInputs] = useState<Record<string, string>>({});
    42→  const [showApiKeys, setShowApiKeys] = useState<Record<string, boolean>>({});
    43→  const [validating, setValidating] = useState<Record<string, boolean>>({});
    44→  const [validationResults, setValidationResults] = useState<Record<string, boolean | null>>({});
    45→
    46→  // Get provider metadata (sync - no SDK loading needed for display)
    47→  const providerMetadataList = PROVIDER_METADATA;
    48→  const providerStatus = router.getProviderStatus();
    49→
    50→  // Check if password is needed
    51→  useEffect(() => {
    52→    if (!encryptionPassword || isPasswordExpired()) {
    53→      // Password needed but don't show prompt automatically
    54→      // User will trigger it when trying to save an API key
    55→    }
    56→  }, [encryptionPassword, isPasswordExpired]);
    57→
    58→  const handlePasswordSubmit = (password: string, hash: string, duration: 'daily' | 'weekly' | 'monthly') => {
    59→    setEncryptionPassword(password, hash, duration);
    60→    setShowPasswordPrompt(false);
    61→
    62→    // If user was trying to save a provider, save it now
    63→    if (selectedProvider && apiKeyInputs[selectedProvider]) {
    64→      saveProviderKey(selectedProvider, apiKeyInputs[selectedProvider], password);
    65→    }
    66→  };
    67→
    68→  const saveProviderKey = async (providerId: string, apiKey: string, password: string) => {
    69→    try {
    70→      await setProviderApiKey(providerId, apiKey, password);
    71→      setApiKeyInputs((prev) => ({ ...prev, [providerId]: '' }));
    72→      setValidationResults((prev) => ({ ...prev, [providerId]: null }));
    73→
    74→      // Store API key in router (will be applied when provider loads)
    75→      router.setProviderApiKey(providerId, apiKey);
    76→
    77→      // Try to load provider and set as active
    78→      const provider = await router.getProvider(providerId);
    79→      if (provider) {
    80→        // Auto-switch to this provider after saving
    81→        const defaultModel = provider.getDefaultModel();
    82→        if (defaultModel) {
    83→          setActiveProvider(providerId, defaultModel.id);
    84→        }
    85→      }
    86→    } catch (error) {
    87→      console.error('Failed to save API key:', error);
    88→      alert('Failed to save API key. Please try again.');
    89→    }
    90→  };
    91→
    92→  const handleSaveApiKey = (providerId: string) => {
    93→    const apiKey = apiKeyInputs[providerId];
    94→    if (!apiKey || !apiKey.trim()) return;
    95→
    96→    // Check if password is needed
    97→    if (!encryptionPassword || isPasswordExpired()) {
    98→      setSelectedProvider(providerId);
    99→      setShowPasswordPrompt(true);
   100→      return;
   101→    }
   102→
   103→    saveProviderKey(providerId, apiKey, encryptionPassword);
   104→  };
   105→
   106→  const handleClearApiKey = (providerId: string) => {
   107→    if (confirm(`Remove API key for ${providerStatus[providerId]?.name}? You'll need to re-enter it to use this provider.`)) {
   108→      clearProviderApiKey(providerId);
   109→      setApiKeyInputs((prev) => ({ ...prev, [providerId]: '' }));
   110→      setValidationResults((prev) => ({ ...prev, [providerId]: null }));
   111→    }
   112→  };
   113→
   114→  const handleTestApiKey = async (providerId: string) => {
   115→    const apiKey = apiKeyInputs[providerId];
   116→    if (!apiKey || !apiKey.trim()) {
   117→      alert('Please enter an API key first.');
   118→      return;
   119→    }
   120→
   121→    setValidating((prev) => ({ ...prev, [providerId]: true }));
   122→
   123→    try {
   124→      // Load provider SDK on-demand for validation
   125→      const provider = await router.getProvider(providerId);
   126→      if (!provider) {
   127→        throw new Error('Provider not found');
   128→      }
   129→
   130→      const isValid = await provider.validateApiKey(apiKey);
   131→      setValidationResults((prev) => ({ ...prev, [providerId]: isValid }));
   132→
   133→      if (isValid) {
   134→        alert(`✓ API key is valid for ${providerStatus[providerId]?.name}!`);
   135→      } else {
   136→        alert(`✗ API key validation failed for ${providerStatus[providerId]?.name}. Please check your key.`);
   137→      }
   138→    } catch (error: unknown) {
   139→      console.error('API key validation error:', error);
   140→      setValidationResults((prev) => ({ ...prev, [providerId]: false }));
   141→      const message = error instanceof Error ? error.message : 'Unknown error';
   142→      alert(`Error validating API key: ${message}`);
   143→    } finally {
   144→      setValidating((prev) => ({ ...prev, [providerId]: false }));
   145→    }
   146→  };
   147→
   148→  const toggleShowApiKey = (providerId: string) => {
   149→    setShowApiKeys((prev) => ({ ...prev, [providerId]: !prev[providerId] }));
   150→  };
   151→
   152→  return (
   153→    <>
   154→      <Modal
   155→        isOpen={isOpen}
   156→        onClose={onClose}
   157→        title="AI Provider Settings"
   158→        maxWidth="2xl"
   159→      >
   160→        <div className="space-y-3">
   161→          {/* Header Description */}
   162→          <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
   163→            <p className="mb-1">
   164→              Configure API keys for AI providers. Your keys are encrypted with AES-256-CBC and stored locally.
   165→            </p>
   166→            <p className="text-[10px]">
   167→              <span className="text-green-500">🟢 Free</span> models available
   168→              {' • '}
   169→              <span className="text-blue-500">🔵 Paid</span> BYOK (Bring Your Own Key)
   170→              {' • '}
   171→              <span className="text-yellow-500">⚠️</span> Requires backend proxy (CORS)
   172→            </p>
   173→          </div>
   174→
   175→          {/* Provider List */}
   176→          <div className="space-y-2 max-h-[60vh] overflow-y-auto">
   177→            {Object.entries(providerMetadataList).map(([providerId, metadata]) => {
   178→              const status = providerStatus[providerId];
   179→              const isConfigured = status?.configured || false;
   180→
   181→              return (
   182→                <div
   183→                  key={providerId}
   184→                  className="p-3 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button"
   185→                >
   186→                  {/* Provider Header */}
   187→                  <div className="flex items-start justify-between mb-2">
   188→                    <div className="flex items-start gap-2.5 flex-1">
   189→                      {/* Provider Favicon */}
   190→                      {metadata.websiteUrl && (
   191→                        <img
   192→                          src={`https://www.google.com/s2/favicons?domain=${new URL(metadata.websiteUrl).hostname}&sz=32`}
   193→                          alt=""
   194→                          className="w-5 h-5 mt-0.5 rounded-sm flex-shrink-0"
   195→                          onError={(e) => {
   196→                            // Hide on error - fall back to no icon
   197→                            (e.target as HTMLImageElement).style.display = 'none';
   198→                          }}
   199→                        />
   200→                      )}
   201→                      <div className="flex-1 min-w-0">
   202→                      <div className="flex items-center gap-1.5 mb-0.5">
   203→                        <h3 className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
   204→                          {metadata.displayName}
   205→                        </h3>
   206→                        {metadata.hasFreeModels && (
   207→                          <span className="text-[10px] px-1.5 py-0.5 bg-green-500/10 text-green-500 rounded">
   208→                            Free Models
   209→                          </span>
   210→                        )}
   211→                        {!metadata.supportsCORS && metadata.requiresProxy && (
   212→                          <span
   213→                            className="text-[10px] px-1.5 py-0.5 bg-yellow-500/10 text-yellow-500 rounded cursor-help"
   214→                            title="This provider blocks direct browser requests (CORS). Use OpenRouter instead - it can access this provider's models and works directly in your browser."
   215→                          >
   216→                            ⚠️ Proxy Required
   217→                          </span>
   218→                        )}
   219→                      </div>
   220→                      <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
   221→                        {metadata.description}
   222→                      </p>
   223→                      <div className="mt-0.5 flex items-center gap-2 text-[10px] text-text-light-secondary dark:text-text-dark-secondary">
   224→                        <span>{status?.modelCount || 0} models</span>
   225→                        {metadata.apiKeyUrl && (
   226→                          <>
   227→                            <span>•</span>
   228→                            <a
   229→                              href={metadata.apiKeyUrl}
   230→                              target="_blank"
   231→                              rel="noopener noreferrer"
   232→                              className="text-accent-blue hover:text-accent-blue-hover"
   233→                            >
   234→                              Get API Key →
   235→                            </a>
   236→                          </>
   237→                        )}
   238→                        {metadata.docsUrl && (
   239→                          <>
   240→                            <span>•</span>
   241→                            <a
   242→                              href={metadata.docsUrl}
   243→                              target="_blank"
   244→                              rel="noopener noreferrer"
   245→                              className="text-accent-blue hover:text-accent-blue-hover"
   246→                            >
   247→                              Documentation →
   248→                            </a>
   249→                          </>
   250→                        )}
   251→                      </div>
   252→                    </div>
   253→                  </div>
   254→
   255→                    {/* Status Badge */}
   256→                    <div className="flex items-center gap-1.5">
   257→                      {isConfigured ? (
   258→                        <span className="text-[10px] px-1.5 py-0.5 bg-green-500/10 text-green-500 rounded">
   259→                          ✓ Configured
   260→                        </span>
   261→                      ) : (
   262→                        <span className="text-[10px] px-1.5 py-0.5 bg-slate-500/10 text-slate-500 rounded">
   263→                          Not Configured
   264→                        </span>
   265→                      )}
   266→                    </div>
   267→                  </div>
   268→
   269→                  {/* API Key Input */}
   270→                  <div className="space-y-1.5">
   271→                    <div className="flex gap-1.5">
   272→                      <div className="flex-1 relative">
   273→                        <input
   274→                          type={showApiKeys[providerId] ? 'text' : 'password'}
   275→                          value={apiKeyInputs[providerId] || ''}
   276→                          onChange={(e) =>
   277→                            setApiKeyInputs((prev) => ({ ...prev, [providerId]: e.target.value }))
   278→                          }
   279→                          placeholder={
   280→                            isConfigured
   281→                              ? 'Enter new API key to replace existing'
   282→                              : `Enter your ${metadata.apiKeyLabel || 'API key'}`
   283→                          }
   284→                          className="w-full px-2.5 py-1.5 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-blue text-text-light-primary dark:text-text-dark-primary text-xs"
   285→                          autoComplete="off"
   286→                        />
   287→                        <button
   288→                          type="button"
   289→                          onClick={() => toggleShowApiKey(providerId)}
   290→                          className="absolute right-2 top-1/2 -translate-y-1/2 text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary text-[10px]"
   291→                        >
   292→                          {showApiKeys[providerId] ? 'Hide' : 'Show'}
   293→                        </button>
   294→                      </div>
   295→                    </div>
   296→
   297→                    {/* Action Buttons */}
   298→                    <div className="flex gap-1.5">
   299→                      <button
   300→                        onClick={() => handleSaveApiKey(providerId)}
