   302→                        className="px-2.5 py-1 bg-accent-blue hover:bg-accent-blue-hover disabled:bg-slate-500/20 disabled:text-slate-500 disabled:cursor-not-allowed text-white rounded-button text-xs transition-all duration-standard ease-smooth"
   303→                      >
   304→                        {isConfigured ? 'Update' : 'Save'}
   305→                      </button>
   306→
   307→                      <button
   308→                        onClick={() => handleTestApiKey(providerId)}
   309→                        disabled={!apiKeyInputs[providerId]?.trim() || validating[providerId]}
   310→                        className="px-2.5 py-1 bg-surface-light-elevated dark:bg-surface-dark-elevated hover:bg-surface-light dark:hover:bg-neutral-800 disabled:opacity-50 disabled:cursor-not-allowed border border-border-light dark:border-border-dark rounded-button text-xs text-text-light-primary dark:text-text-dark-primary transition-all duration-standard ease-smooth"
